struct TrieNode
{
    unordered_map<char, TrieNode *> children; // recall unordered_map<char, int> from frequency counting — here, char maps to the NEXT node
    bool isEndOfWord = false;
};

#include <iostream>
#include <unordered_map>
#include <string>

using namespace std;

struct TrieNode
{
    unordered_map<char, TrieNode *> children;
    bool isEndOfWord = false;
};

class Trie
{
private:
    TrieNode *root;

public:
    Trie()
    {
        root = new TrieNode();
    }

    void insert(string word)
    {
        TrieNode *current = root;
        for (char c : word)
        {
            if (current->children.find(c) == current->children.end())
            {
                current->children[c] = new TrieNode(); // create the path if it doesn't exist yet
            }
            current = current->children[c];
        }
        current->isEndOfWord = true; // mark the END of this specific word
    }

    bool search(string word)
    {
        TrieNode *current = root;
        for (char c : word)
        {
            if (current->children.find(c) == current->children.end())
            {
                return false; // path doesn't exist — word was never inserted
            }
            current = current->children[c];
        }
        return current->isEndOfWord; // path exists, but was it marked as a COMPLETE word?
    }

    bool startsWith(string prefix)
    {
        TrieNode *current = root;
        for (char c : prefix)
        {
            if (current->children.find(c) == current->children.end())
            {
                return false;
            }
            current = current->children[c];
        }
        return true; // the path exists — SOME word starts with this prefix
    }
};

int main()
{
    Trie trie;
    trie.insert("cat");
    trie.insert("car");

    cout << trie.search("cat") << endl;
    cout << trie.search("ca") << endl;
    cout << trie.startsWith("ca") << endl;

    return 0;
}

